#include <fstream>
#include <iostream>
#include <sstream>
#include <string>
#include <unordered_map>
#include <vector>
#include <regex>

// Mapping from ANTLR token type names to clang-style names
std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Void", "void" },
  { "Const", "const" },
  { "Return", "return" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "LeftBrace", "l_brace" },
  { "RightBrace", "r_brace" },
  { "Constant", "numeric_constant" },
  { "Semi", "semi" },
  { "Comma", "comma" },
  { "Equal", "equal" },
  { "Plus", "plus" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
  { "Less", "less" },
  { "LessEqual", "lessequal" },
  { "Greater", "greater" },
  { "GreaterEqual", "greaterequal" },
  { "EqualEqual", "equalequal" },
  { "ExclaimEqual", "exclaimequal" },
  { "Exclaim", "exclaim" },
  { "AmpAmp", "ampamp" },
  { "PipePipe", "pipepipe" },
  { "EOF", "eof" },
};

// Preprocessing directive: maps physical line to (logical line, filename)
struct Directive {
  int physicalLine;   // 1-based line number in the preprocessed file where the # directive appears
  int logicalLine;    // the logical line number that the NEXT source line maps to
  std::string file;   // the filename from the directive
};

// Parse all preprocessing directives from the raw source text
std::vector<Directive>
parseDirectives(const std::string& source)
{
  std::vector<Directive> directives;
  std::istringstream stream(source);
  std::string line;
  int physLine = 0;

  // Regex to match preprocessing line directives:
  // # linenum "filename" [flags]
  std::regex directiveRegex(R"(^\s*#\s+(\d+)\s+"([^"]*)")");

  while (std::getline(stream, line)) {
    physLine++;
    std::smatch match;
    if (std::regex_search(line, match, directiveRegex)) {
      Directive d;
      d.physicalLine = physLine;
      d.logicalLine = std::stoi(match[1].str());
      d.file = match[2].str();
      directives.push_back(d);
    }
  }
  return directives;
}

// Given a physical line number, find the logical line and filename
void
getLogicalPos(const std::vector<Directive>& directives,
              int physLine,
              int& logicalLine,
              std::string& file)
{
  // Find the most recent directive whose physicalLine < physLine
  // (the directive is on a line before the token's line)
  const Directive* best = nullptr;
  for (auto& d : directives) {
    if (d.physicalLine < physLine) {
      if (!best || d.physicalLine > best->physicalLine) {
        best = &d;
      }
    }
  }

  if (best) {
    // The directive at physicalLine says the NEXT line (physicalLine+1) is logicalLine
    // So for a token at physLine: logicalLine = best->logicalLine + (physLine - best->physicalLine - 1)
    logicalLine = best->logicalLine + (physLine - best->physicalLine - 1);
    file = best->file;
  } else {
    // No directive found, use physical line as-is
    logicalLine = physLine;
    file = "";
  }
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer,
            const std::vector<Directive>& directives,
            const std::string& source,
            int tokenIndex)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>";

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // Get physical position from ANTLR
  int physLine = token->getLine();
  int physCol = token->getCharPositionInLine() + 1; // 1-based column

  // Compute logical position
  int logicalLine = physLine;
  std::string file;
  getLogicalPos(directives, physLine, logicalLine, file);

  // Build Loc string
  std::string locInfo = " Loc=<" + file + ":" +
                        std::to_string(logicalLine) + ":" +
                        std::to_string(physCol) + ">";

  // Determine StartOfLine and LeadingSpace
  bool startOfLine = false;
  bool leadingSpace = false;

  if (token->getType() != antlr4::Token::EOF) {
    // StartOfLine: this token is the first token on its physical line
    // Check if the previous token was on a different physical line
    if (tokenIndex == 0) {
      // First token - check if it's at the start of its line
      startOfLine = (physCol == 1);
    } else {
      auto prevToken = tokens.getTokens()[tokenIndex - 1];
      int prevPhysLine = prevToken->getLine();
      if (prevPhysLine != physLine) {
        // Previous token was on a different line, so this is start of line
        startOfLine = true;
      }
    }

    // LeadingSpace: there's whitespace before this token
    // Check the raw source text: if the character before the token start is a space/tab
    int tokenStart = token->getStartIndex();
    if (tokenStart > 0 && tokenStart < (int)source.size()) {
      char prevChar = source[tokenStart - 1];
      if (prevChar == ' ' || prevChar == '\t') {
        leadingSpace = true;
      }
    }
  }

  // Output
  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '" << "'";

  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;
}

int
main(int argc, char* argv[])
{
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // Read entire source into a string for directive parsing and leading space detection
  std::stringstream buffer;
  buffer << inFile.rdbuf();
  std::string source = buffer.str();

  // Parse preprocessing directives
  std::vector<Directive> directives = parseDirectives(source);

  // Run ANTLR lexer
  antlr4::ANTLRInputStream input(source);
  SYsULexer lexer(&input);

  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  int idx = 0;
  for (auto&& token : tokens.getTokens()) {
    print_token(token, tokens, outFile, lexer, directives, source, idx);
    idx++;
  }
}

